/**
 * MES系统工具函数
 * 包含所有模块共享的通用工具函数
 */

import { STATUS_TYPE_MAP, RECORD_TYPE_TEXT_MAP, RECORD_TYPE_TAG_MAP } from '@/constants'

// ==================== 状态处理函数 ====================

/**
 * 获取状态对应的 Element Plus 标签类型
 * @param status 状态值
 * @returns 标签类型
 */
export const getStatusType = (status: string): string => {
  return STATUS_TYPE_MAP[status] || 'info'
}

/**
 * 获取记录类型对应的文本
 * @param type 记录类型
 * @returns 类型文本
 */
export const getRecordTypeText = (type: string): string => {
  return RECORD_TYPE_TEXT_MAP[type] || type
}

/**
 * 获取记录类型对应的标签类型
 * @param type 记录类型
 * @returns 标签类型
 */
export const getRecordTypeType = (type: string): string => {
  return RECORD_TYPE_TAG_MAP[type] || 'info'
}

// ==================== 时间处理函数 ====================

/**
 * 格式化日期时间为字符串
 * @param date 日期对象
 * @returns 格式化后的字符串 (YYYY-MM-DD HH:mm:ss)
 */
export const formatDateTime = (date: Date = new Date()): string => {
  const year = date.getFullYear()
  const month = String(date.getMonth() + 1).padStart(2, '0')
  const day = String(date.getDate()).padStart(2, '0')
  const hours = String(date.getHours()).padStart(2, '0')
  const minutes = String(date.getMinutes()).padStart(2, '0')
  const seconds = String(date.getSeconds()).padStart(2, '0')
  return `${year}-${month}-${day} ${hours}:${minutes}:${seconds}`
}

/**
 * 格式化时间为 HH:mm 格式
 * @param date 日期对象
 * @returns 格式化后的时间字符串
 */
export const formatTime = (date: Date = new Date()): string => {
  const hours = String(date.getHours()).padStart(2, '0')
  const minutes = String(date.getMinutes()).padStart(2, '0')
  return `${hours}:${minutes}`
}

/**
 * 生成批次号
 * @returns 批次号字符串 (BT + YYYYMMDD + 流水号)
 */
export const generateBatchNo = (): string => {
  const date = new Date()
  const dateStr = `${date.getFullYear()}${String(date.getMonth() + 1).padStart(2, '0')}${String(date.getDate()).padStart(2, '0')}`
  const randomNum = String(Math.floor(Math.random() * 900) + 100).padStart(3, '0')
  return `BT${dateStr}${randomNum}`
}

// ==================== 数据生成函数 ====================

/**
 * 生成历史数据数组
 * @param baseValue 基础值
 * @param count 数据点数量
 * @returns 历史数据数组
 */
export const generateHistoryData = (baseValue: number, count: number = 12): Array<{ time: string; value: number }> => {
  const data: Array<{ time: string; value: number }> = []
  const now = new Date()

  for (let i = count - 1; i >= 0; i--) {
    const time = new Date(now.getTime() - i * 5 * 60 * 1000)
    const timeStr = `${String(time.getHours()).padStart(2, '0')}:${String(time.getMinutes()).padStart(2, '0')}`
    const variation = (Math.random() - 0.5) * baseValue * 0.2
    const value = Math.max(0, Math.round((baseValue + variation) * 10) / 10)
    data.push({ time: timeStr, value })
  }

  return data
}

/**
 * 生成随机条码
 * @returns 随机条码字符串
 */
export const generateRandomBarcode = (): string => {
  const prefixes = ['MAT-GLUE', 'MAT-COLOR', 'MAT-POWDER', 'MAT-ADD']
  const prefix = prefixes[Math.floor(Math.random() * prefixes.length)]
  const num = String(Math.floor(Math.random() * 900) + 100).padStart(3, '0')
  return `${prefix}-${num}`
}

// ==================== 验证函数 ====================

/**
 * 验证批次号格式
 * @param batchNo 批次号
 * @returns 是否有效
 */
export const validateBatchNoFormat = (batchNo: string): boolean => {
  const pattern = /^BT\d{8}\d{3}$/
  return pattern.test(batchNo)
}

/**
 * 验证批次号是否在有效列表中
 * @param batchNo 批次号
 * @param validList 有效批次号列表
 * @returns 是否存在
 */
export const isBatchNoValid = (batchNo: string, validList: string[]): boolean => {
  return validList.includes(batchNo.trim())
}

// ==================== 计算函数 ====================

/**
 * 计算百分比
 * @param current 当前值
 * @param target 目标值
 * @returns 百分比 (0-100)
 */
export const calculatePercentage = (current: number, target: number): number => {
  if (target === 0) return 0
  return Math.min(100, Math.round((current / target) * 100))
}

/**
 * 计算偏差率
 * @param actual 实际值
 * @param theory 理论值
 * @returns 偏差率 (%)
 */
export const calculateDeviation = (actual: number, theory: number): number => {
  if (theory === 0) return 0
  return Math.round(((actual - theory) / theory) * 100 * 10) / 10
}

/**
 * 判断偏差是否在允许范围内
 * @param actual 实际值
 * @param theory 理论值
 * @param tolerance 允许偏差 (默认5%)
 * @returns 是否正常
 */
export const isWithinTolerance = (actual: number, theory: number, tolerance: number = 5): boolean => {
  const deviation = Math.abs(calculateDeviation(actual, theory))
  return deviation <= tolerance
}

// ==================== 格式化函数 ====================

/**
 * 格式化数字，保留指定小数位
 * @param value 数值
 * @param decimals 小数位数
 * @returns 格式化后的字符串
 */
export const formatNumber = (value: number, decimals: number = 2): string => {
  return value.toFixed(decimals)
}

/**
 * 格式化文件大小
 * @param bytes 字节数
 * @returns 格式化后的字符串
 */
export const formatFileSize = (bytes: number): string => {
  if (bytes === 0) return '0 B'
  const k = 1024
  const sizes = ['B', 'KB', 'MB', 'GB', 'TB']
  const i = Math.floor(Math.log(bytes) / Math.log(k))
  return `${parseFloat((bytes / Math.pow(k, i)).toFixed(2))} ${sizes[i]}`
}
